import { axiosCall } from "../../Data";

export const setAdmin = (arg) => (dispatch) => {
	axiosCall('post', '/supers', arg, {withCredentials: true})
	.then(res => dispatch({ type: "SET_ADMIN", payload: res}))
  .catch(err => dispatch({ type: "ERR_MESSAGE", payload: err }));
};
